Bash(node -e "
const fs = require\('fs'\);
let lines = fs.readFileSync\('index.html', 'utf8'\).split\('\\n'\);

// Find about-imgs div and remove it including its contents until closing div
let start = -1, end = -1, depth = 0;
for \(let i = 0; i < lines.length; i++\) {
  if \(lines[i].includes\('about-imgs'\)\) {
    start = i;
    depth = 1;
    continue;
  }
  if \(start !== -1 && depth > 0\) {
    if \(lines[i].includes\('<div'\)\) depth++;
    if \(lines[i].includes\('</div>'\)\) depth--;
    if \(depth === 0\) {
      end = i;
      break;
    }
  }
}

if \(start !== -1 && end !== -1\) {
  lines.splice\(start, end - start + 1\);
  console.log\('Removed lines', start, 'to', end\);
}

fs.writeFileSync\('index.html', lines.join\('\\n'\), 'utf8'\);
console.log\('Done'\);
")
